Actually I think we can skip on the parse functions for now and just do everything in the decoder

```rust
impl Decoder for SbpFramer {
    fn decode(&mut self, src: &mut BytesMut) -> Result<Option<Self::Item>, Self::Error> {
        let start = match src.iter().position(|b| b == &PREAMBLE) {
            Some(idx) => idx,
            None => {
                src.clear();
                return Ok(None);
            }
        };
        src.advance(start);
        if src.len() < HEADER_LEN {
            src.reserve(MAX_FRAME_LEN);
            return Ok(None);
        }
        let payload_len = src[5] as usize;
        let at = HEADER_LEN + payload_len + CRC_LEN;
        if src.len() < at {
            src.reserve(MAX_FRAME_LEN);
            return Ok(None);
        }
        let frame = SbpFrame(src.split_to(at));
        frame.check_crc()?;
        Ok(Some(frame))
    }
}
```

simplifies things not having to worry about parsing from `&[u8]` and we can add it later if we want it

